sql:
SELECT vehicle_id
FROM vehicle_fuel_efficiency
WHERE fuel_consumption_comb_mpg = (SELECT MAX(fuel_consumption_comb_mpg) FROM vehicle_fuel_efficiency);

external_knowledge:
- 'Active vehicles' refers to vehicles currently in production or available in the market; 
- 'Automatic transmission' is a type of transmission that automatically changes gears; 
- 'More than three cylinders' refers to the number of cylinders in the vehicle engine; 
- 'Below 8.0 L/100 km' refers to the average fuel consumption as a measure of fuel efficiency.

